interface IAccountSupportProfile extends Pick<Account, 'email' | 'phone' | 'softDescriptor'> {
  city: string;
  country: string;
  line1: string;
  line2: string;
  postalCode: string;
  region: string;
  social: {
    provider: string;
    url: string;
  }[];
}

type SupportProfileAddressPayload = AddressAttributes & {
  accountId?: string;
  addressType: AddressType;
  id?: string;
};

type AddressReviewState = {
  account: IAccountSupportProfile;
  address: SupportProfileAddressPayload;
  suggestedAddress: SmartySuggestedAddress;
};

const normalizeAddressPart = (value?: string | null) =>
  value?.toString().trim().replace(/\s+/g, ' ').toUpperCase() ?? '';

const suggestionIsDifferent = (
  address: SupportProfileAddressPayload,
  suggestion: SmartySuggestedAddress | undefined
) => {
  if (!suggestion) {
    return false;
  }

  const comparisons: Array<[string | null | undefined, string | null | undefined]> = [
    [address.line1, suggestion.delivery_line_1],
    [address.city, suggestion.components.city_name],
    [address.region, suggestion.components.state_abbreviation],
    [address.postalCode, suggestion.components.zipcode],
  ];

  return comparisons.some(
    ([current, proposed]) => normalizeAddressPart(current) !== normalizeAddressPart(proposed)
  );
};

const mergeSuggestedAddress = (
  address: SupportProfileAddressPayload,
  suggestion: SmartySuggestedAddress
): SupportProfileAddressPayload => ({
  ...address,
  city: suggestion.components.city_name ?? address.city,
  line1: suggestion.delivery_line_1 ?? address.line1,
  postalCode: suggestion.components.zipcode ?? address.postalCode,
  region: suggestion.components.state_abbreviation ?? address.region,
});

const toSmartyAddress = (address: SupportProfileAddressPayload): SmartyAddress => ({
  city: address.city,
  secondary: address.line2 ?? '',
  state: address.region,
  street_line: address.line1,
  zipcode: address.postalCode,
});

const formatAddressLines = (address: SupportProfileAddressPayload) => {
  const cityState = [address.city, address.region].filter(Boolean).join(', ');
  const postalLine = [cityState, address.postalCode].filter(Boolean).join(' ');

  return [address.line1, address.line2, postalLine, address.country]
    .filter((line) => !!line && line !== ' ')
    .map((line) => line as string);
};

